import{assert}from"./asserts.js";function clamp(r,t,n){return Math.min(Math.max(r,t),n)}var cosh=function(){var r="cosh"in Math?Math.cosh:function(r){r=Math.exp(r);return(r+1/r)/2};return r}();function roundUpToPowerOfTwo(r){return assert(0<r,29),Math.pow(2,Math.ceil(Math.log(r)/Math.LN2))}function squaredSegmentDistance(r,t,n,e,a,o){var u,s=a-n,i=o-e;return 0==s&&0==i||(1<(u=((r-n)*s+(t-e)*i)/(s*s+i*i))?(n=a,e=o):0<u&&(n+=s*u,e+=i*u)),squaredDistance(r,t,n,e)}function squaredDistance(r,t,n,e){n-=r,r=e-t;return n*n+r*r}function solveLinearSystem(r){for(var t=r.length,n=0;n<t;n++){for(var e=n,a=Math.abs(r[n][n]),o=n+1;o<t;o++){var u=Math.abs(r[o][n]);a<u&&(a=u,e=o)}if(0===a)return null;var s=r[e];r[e]=r[n],r[n]=s;for(var i=n+1;i<t;i++)for(var c=-r[i][n]/r[n][n],f=n;f<t+1;f++)n==f?r[i][f]=0:r[i][f]+=c*r[n][f]}for(var h=new Array(t),l=t-1;0<=l;l--){h[l]=r[l][t]/r[l][l];for(var v=l-1;0<=v;v--)r[v][t]-=r[v][l]*h[l]}return h}function toDegrees(r){return 180*r/Math.PI}function toRadians(r){return r*Math.PI/180}function modulo(r,t){r%=t;return r*t<0?r+t:r}function lerp(r,t,n){return r+n*(t-r)}export{clamp,cosh,roundUpToPowerOfTwo,squaredSegmentDistance,squaredDistance,solveLinearSystem,toDegrees,toRadians,modulo,lerp};